"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[752],{2139:e=>{e.exports=JSON.parse('{"functions":[],"properties":[],"types":[{"name":"PollingContext","desc":"Configuration passed to the Polling loop on startup.","fields":[{"name":"hash","lua_type":"MemoryStoreHashMap","desc":"The MemoryStore hash map to poll"},{"name":"read","lua_type":"(key: string) -> number?","desc":"Function to read an event\'s end-time"},{"name":"pollForKeys","lua_type":"{string}","desc":"Array of event keys to watch"}],"source":{"line":34,"path":"packages/admin-abuse/src/Polling.luau"}}],"name":"Polling","desc":"A background loop that periodically reads from MemoryStoreService to discover\\nevents started by other servers. This is the fallback synchronization mechanism \u2014\\nif a server misses the MessagingService broadcast, the Polling loop will pick up\\nthe event on its next cycle.\\n\\nThe loop runs every `memstore_update_interval` seconds (default: 5). For each key\\nin `pollForKeys`, it:\\n\\n1. Reads the stored end-time from MemoryStoreService via [Ping].read\\n2. If the event has expired (`now >= endTime`), clears local state and removes the\\n   key from the hash map\\n3. If the event is still active and not already running locally, activates it\\n   (checking [Cache] to avoid duplicates)","realm":["Server"],"since":"0.1.0","private":true,"source":{"line":23,"path":"packages/admin-abuse/src/Polling.luau"}}')}}]);